const BASE = 'https://mirador-villarrica-chatbot.vercel.app/assets';
const TOUR_URL = 'https://lanube360.com/mirador-de-villarrica/';

const text = `Listo, aquí tienes el tour 360° 👇

Vas a ver el plano con la orientación geográfica y dos vistas más de los alrededores.

Las parcelas están codificadas por color:
🔴 **Rojo:** vendida
🔵 **Azul:** reservada
⚪ **Blanco:** disponible

Revísalo con calma y dime cuál te llama más la atención — la revisamos juntos en vivo y te confirmo disponibilidad y precios al instante.`;

return [{ json: {
  type: 'tour360_floating',
  url: TOUR_URL,
  title: 'Tour 360° · Mirador de Villarrica',
  caption: 'Recorre el proyecto desde tu dispositivo',
  poster: `${BASE}/banner-volcan.jpg`,
  description_detailed: 'Tour virtual 360° interactivo del proyecto Mirador de Villarrica en Colico, La Araucanía. Permite al lead recorrer el proyecto desde su dispositivo: arrastrando con el dedo en móvil (o moviendo el teléfono usando el girocopio) y arrastrando el mouse en PC. Incluye 3 vistas: plano/masterplan con orientación geográfica + 2 vistas reales de los alrededores (bosque nativo, caminos internos, volcán, lago). Plano codificado por color: rojo=vendida, azul=reservada, blanco=disponible.',
  tool_output_text: text,
} }];
